import{_ as t,o as n,c as i,a2 as r}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"spv/laporan-harian.md","filePath":"spv/laporan-harian.md"}'),e={name:"spv/laporan-harian.md"};function s(d,a,o,u,g,l){return n(),i("div",null,[...a[0]||(a[0]=[r('<h2 id="bab-3-laporan-harian-9-tab-fase-2" tabindex="-1">BAB 3: LAPORAN HARIAN (9 TAB + FASE 2) <a class="header-anchor" href="#bab-3-laporan-harian-9-tab-fase-2" aria-label="Permalink to &quot;BAB 3: LAPORAN HARIAN (9 TAB + FASE 2)&quot;">​</a></h2><h3 id="_3-1-fitur-penting-sebelum-mulai" tabindex="-1">3.1 Fitur Penting Sebelum Mulai <a class="header-anchor" href="#_3-1-fitur-penting-sebelum-mulai" aria-label="Permalink to &quot;3.1 Fitur Penting Sebelum Mulai&quot;">​</a></h3><p>Sebelum mengisi laporan, kenali dulu 3 fitur perlindungan data yang bekerja diam-diam di balik layar:</p><ol><li><p><strong>Simpan Otomatis (Autosave):</strong> Setiap huruf yang Anda ketik langsung tersimpan di memori browser HP Anda. Jika aplikasi tertutup mendadak (baterai habis, sinyal putus), data Anda <strong>tidak hilang</strong>. Saat Anda buka kembali, semua isian akan tetap ada.</p></li><li><p><strong>Perlindungan Anti-Klik Ganda:</strong> Setelah Anda menekan tombol &quot;Kirim&quot;, sistem akan menahan semua klik selama 10 detik. Ini mencegah laporan terkirim 2 kali jika Anda tidak sengaja menekan tombol berkali-kali.</p></li><li><p><strong>Perlindungan Antar-Outlet:</strong> Jika Anda login sebagai SPV Perintis, lalu besok login sebagai SPV Dg Tata (misalnya karena pindah tugas), sistem akan otomatis membuang data lama yang tidak cocok dengan outlet Anda saat ini. Data outlet lain tidak akan pernah tercampur.</p></li></ol><h3 id="_3-2-tab-1-jual-penjualan-shift-1-konteks" tabindex="-1">3.2 Tab 1: JUAL (Penjualan Shift 1 &amp; Konteks) <a class="header-anchor" href="#_3-2-tab-1-jual-penjualan-shift-1-konteks" aria-label="Permalink to &quot;3.2 Tab 1: JUAL (Penjualan Shift 1 &amp; Konteks)&quot;">​</a></h3><p>Tab ini adalah fondasi utama laporan harian. Data di sini menjadi bahan kalkulasi omset, target, dan tren di Dashboard GM.</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Cara Mengisi</th><th>Catatan Penting</th></tr></thead><tbody><tr><td><strong>Nama Supervisor</strong></td><td>Ketik nama Anda, sistem akan memunculkan daftar pilihan otomatis</td><td>Hanya nama staf dari outlet Anda yang muncul</td></tr><tr><td><strong>Outlet</strong></td><td>Sudah terkunci otomatis (abu-abu), tidak bisa diedit</td><td>Ditentukan dari PIN saat login</td></tr><tr><td><strong>Tanggal Laporan</strong></td><td>Pilih tanggal dari kalender</td><td>Setelah memilih tanggal, <strong>tunggu sebentar</strong> — sistem sedang menarik angka target omset dari database</td></tr><tr><td><strong>Jam Masuk</strong></td><td>Pilih jam Anda tiba di outlet</td><td>Digunakan untuk menghitung ketepatan waktu</td></tr><tr><td><strong>Cuaca Dominan</strong></td><td>Pilih salah satu: Cerah/Panas, Mendung, Hujan Gerimis, Hujan Badai</td><td>Digunakan mesin AI untuk menganalisis pengaruh cuaca terhadap penjualan</td></tr><tr><td><strong>Profil Pengunjung</strong></td><td>Pilih tipe pengunjung yang paling dominan hari ini</td><td>Digunakan untuk strategi pemasaran</td></tr><tr><td><strong>Target Omset (Rp)</strong></td><td><strong>Tidak perlu diisi</strong> — angka muncul otomatis</td><td>Diambil dari target yang Anda atur di Pengaturan Parameter</td></tr><tr><td><strong>Omset Shift 1 (Rp)</strong></td><td>Ketik angka penjualan Shift 1</td><td>Saat diketik, bar hijau di bawah akan bergerak menunjukkan persentase pencapaian</td></tr><tr><td><strong>Omset Shift 2</strong></td><td>Tidak bisa diisi sekarang (abu-abu)</td><td>Diisi besok pagi di Fase 2</td></tr></tbody></table><h3 id="_3-3-tab-2-kas-audit-uang-di-laci-kasir" tabindex="-1">3.3 Tab 2: KAS (Audit Uang di Laci Kasir) <a class="header-anchor" href="#_3-3-tab-2-kas-audit-uang-di-laci-kasir" aria-label="Permalink to &quot;3.3 Tab 2: KAS (Audit Uang di Laci Kasir)&quot;">​</a></h3><p>Tab ini merekam hasil penghitungan uang fisik di laci kasir. Anda bisa mengaudit lebih dari sekali dalam satu shift.</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Cara Mengisi</th><th>Catatan Penting</th></tr></thead><tbody><tr><td><strong>Modal Awal Kasir</strong></td><td>Ketik jumlah uang receh standar saat buka (umumnya Rp 200.000)</td><td>—</td></tr><tr><td><strong>Jam Audit</strong></td><td>Pilih jam saat Anda menghitung uang</td><td>—</td></tr><tr><td><strong>Total QRIS</strong></td><td>Ketik total uang masuk via QRIS</td><td>—</td></tr><tr><td><strong>Total Tunai</strong></td><td>Ketik total uang tunai fisik di laci (belum dikurangi modal awal)</td><td>—</td></tr><tr><td><strong>Aktual (Sistem)</strong></td><td>Ketik angka total penjualan menurut mesin kasir (POS)</td><td>Ini adalah angka &quot;kebenaran&quot; yang jadi pembanding</td></tr><tr><td><strong>Selisih (Rp)</strong></td><td>Ketik hasil selisih antara uang fisik dan data sistem</td><td>Jika minus, angka akan berwarna <strong>merah</strong> — ini yang dipantau GM</td></tr><tr><td><strong>Catatan Selisih</strong></td><td>Jelaskan kenapa ada selisih (jika ada)</td><td><strong>Sangat penting!</strong> Tanpa penjelasan, GM bisa salah mengira ini sebagai kecurangan</td></tr></tbody></table><p><strong>Tombol penting:</strong></p><ul><li><strong>Tombol &quot;TAMBAH&quot; (kanan atas):</strong> Tekan jika Anda mengaudit laci kasir lebih dari sekali (misal: siang dan malam).</li><li><strong>Tombol &quot;HAPUS&quot; (merah, di setiap baris):</strong> Hapus baris audit tertentu jika salah tekan.</li></ul><h3 id="_3-4-tab-3-staff-absensi-kepatuhan-sop" tabindex="-1">3.4 Tab 3: STAFF (Absensi &amp; Kepatuhan SOP) <a class="header-anchor" href="#_3-4-tab-3-staff-absensi-kepatuhan-sop" aria-label="Permalink to &quot;3.4 Tab 3: STAFF (Absensi &amp; Kepatuhan SOP)&quot;">​</a></h3><p>Tab ini adalah salah satu yang paling berpengaruh terhadap KPI di Dashboard GM. Setiap pilihan yang Anda buat di sini akan langsung mempengaruhi skor kedisiplinan staf.</p><p><strong>Langkah mengisi:</strong></p><ol><li>Pilih nama staf dari dropdown <strong>&quot;PILIH STAFF&quot;</strong></li><li>Tekan tombol <strong>&quot;TAMBAH&quot;</strong> untuk menambahkan ke daftar evaluasi</li><li>Isi penilaian untuk setiap staf yang sudah ditambahkan</li></ol><p><strong>Tombol khusus:</strong></p><ul><li><strong>+ STAFF BARU:</strong> Untuk mendaftarkan staf freelance/cabutan yang belum ada di database</li><li><strong>+ PINJAM STAF:</strong> Untuk mengambil nama staf dari outlet lain (jika ada pertukaran shift)</li></ul><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Pilihan</th><th>Dampak ke Dashboard GM</th></tr></thead><tbody><tr><td><strong>Metode Penilaian</strong></td><td>Dinilai Langsung / Dinilai via Absensi</td><td>—</td></tr><tr><td><strong>Status Kehadiran</strong></td><td>Hadir, Terlambat, Izin, Sakit, Alpha</td><td>Memilih &quot;Terlambat&quot; <strong>langsung menurunkan</strong> persentase kedisiplinan staf di Dashboard GM</td></tr><tr><td><strong>Keramahan Terlewat?</strong></td><td>Ya (Miss) / Tidak (Aman)</td><td>Memilih &quot;Ya (Miss)&quot; <strong>langsung menurunkan</strong> skor SOP Keramahan. Tidak muncul untuk posisi Kitchen</td></tr><tr><td><strong>Catatan Khusus</strong></td><td>Teks bebas</td><td>Jelaskan alasan keterlambatan atau pelanggaran</td></tr></tbody></table><h3 id="_3-5-tab-4-brief-evaluasi-shift-briefing" tabindex="-1">3.5 Tab 4: BRIEF (Evaluasi Shift &amp; Briefing) <a class="header-anchor" href="#_3-5-tab-4-brief-evaluasi-shift-briefing" aria-label="Permalink to &quot;3.5 Tab 4: BRIEF (Evaluasi Shift &amp; Briefing)&quot;">​</a></h3><p>Tab ini berisi analisis kualitatif Anda sebagai SPV. Kata-kata yang Anda ketik di sini akan dibaca oleh mesin <em>Text Mining</em> di Dashboard GM.</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Contoh</th></tr></thead><tbody><tr><td><strong>Target Hari Ini</strong></td><td>&quot;Capai 120 struk, fokus upselling dessert&quot;</td></tr><tr><td><strong>Fokus Perilaku</strong></td><td>&quot;Ingatkan tim untuk senyum dan tawarkan add-on&quot;</td></tr><tr><td><strong>Masalah Shift Kemarin</strong></td><td>&quot;Kulkas kurang dingin, es batu cepat cair&quot;</td></tr><tr><td><strong>Solusi Disepakati</strong></td><td>&quot;Sudah panggil teknisi, sementara pakai es dari luar&quot;</td></tr></tbody></table><h3 id="_3-6-tab-5-qc-quality-control-produk" tabindex="-1">3.6 Tab 5: QC (Quality Control Produk) <a class="header-anchor" href="#_3-6-tab-5-qc-quality-control-produk" aria-label="Permalink to &quot;3.6 Tab 5: QC (Quality Control Produk)&quot;">​</a></h3><p>Dibagi menjadi dua bagian:</p><p><strong>A. QC Espresso (Wajib diisi setiap hari)</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Pilihan</th></tr></thead><tbody><tr><td><strong>Jam Kalibrasi</strong></td><td>Jam berapa grinder/espresso machine ditarik</td></tr><tr><td><strong>Kondisi</strong></td><td>Baik/Standar, Pahit/Bitter, Asam/Sour, Watery</td></tr><tr><td><strong>Keterangan Adjust</strong></td><td>Contoh: &quot;Ubah grind size jadi 2.5, ekstraksi terlalu cepat&quot;</td></tr></tbody></table><p><strong>B. QC Menu Lainnya (Tekan &quot;TAMBAH ITEM&quot; untuk menambah)</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Cara Mengisi</th></tr></thead><tbody><tr><td><strong>Jam</strong></td><td>Jam pengecekan</td></tr><tr><td><strong>Kategori &amp; Produk</strong></td><td>Pilih Minuman/Makanan/Snack, lalu ketuk input produk untuk mencari nama menu</td></tr><tr><td><strong>Status Temuan</strong></td><td>Pilihan berubah sesuai kategori (misal: Makanan → &quot;Tidak Fresh&quot;; Minuman → &quot;Layering Salah&quot;)</td></tr><tr><td><strong>Catatan Tindakan</strong></td><td>Langkah koreksi yang diambil</td></tr></tbody></table><h3 id="_3-7-tab-6-bersih-inspeksi-kebersihan-8-area" tabindex="-1">3.7 Tab 6: BERSIH (Inspeksi Kebersihan 8 Area) <a class="header-anchor" href="#_3-7-tab-6-bersih-inspeksi-kebersihan-8-area" aria-label="Permalink to &quot;3.7 Tab 6: BERSIH (Inspeksi Kebersihan 8 Area)&quot;">​</a></h3><p>Tab ini mewajibkan Anda menginspeksi <strong>8 area kafe</strong> satu per satu: Kaca, Lantai, Tembok, Toilet, Wastafel, Parking Area, Bar, Musholah.</p><p>Setiap area berbentuk kotak lipatan (Accordion) yang harus Anda buka dan isi:</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Pilihan</th><th>Dampak</th></tr></thead><tbody><tr><td><strong>Status Kebersihan</strong></td><td>Bersih, Cukup Bersih, Kotor</td><td>Rata-rata dari 8 area ini membentuk <strong>Skor Kebersihan (Hygiene Score)</strong> di Dashboard GM</td></tr><tr><td><strong>Skor</strong></td><td>Otomatis terisi (Bersih=100, Cukup=70, Kotor=40), tapi Anda bisa ubah manual</td><td>Misal: area &quot;Cukup Bersih&quot; tapi hampir sempurna, Anda boleh ubah jadi 85</td></tr><tr><td><strong>Centang Alasan</strong></td><td>Kotak-kotak centang yang muncul otomatis sesuai area dan status</td><td>Cukup centang, tidak perlu mengetik — menghemat waktu Anda</td></tr></tbody></table><blockquote><p><strong>Kenapa menggunakan centang, bukan ketik?</strong> Fitur centang sengaja dipilih agar Anda lebih cepat selesai. Pilihan-pilihan yang tersedia diambil dari <strong>catatan laporan fisik Zero Cafe sebelumnya</strong> — jadi semua pilihan memang relevan dengan kondisi nyata di lapangan.</p></blockquote><p><strong>Apa yang terjadi dengan data kebersihan ini?</strong> Selain disimpan ke database utama, sistem juga otomatis <strong>mencetak PDF Checklist Kebersihan Harian</strong> yang tersimpan permanen di Google Drive sebagai bukti fisik.</p><h3 id="_3-8-tab-7-komplain-laporan-keluhan-pelanggan" tabindex="-1">3.8 Tab 7: KOMPLAIN (Laporan Keluhan Pelanggan) <a class="header-anchor" href="#_3-8-tab-7-komplain-laporan-keluhan-pelanggan" aria-label="Permalink to &quot;3.8 Tab 7: KOMPLAIN (Laporan Keluhan Pelanggan)&quot;">​</a></h3><p>Gunakan tombol <strong>&quot;TAMBAH&quot;</strong> untuk menambah baris insiden (bisa diulang tanpa batas). Gunakan tombol <strong>&quot;HAPUS&quot;</strong> untuk menghapus baris jika salah.</p><p><strong>Bagian Atas — Statistik:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Total Kasus Komplain</strong></td><td>Angka total komplain hari ini</td></tr><tr><td><strong>Total Remake</strong></td><td>Jumlah produk yang harus dibikin ulang</td></tr><tr><td><strong>Analisis Remake ≥3</strong></td><td>Kotak peringatan merah ini <strong>hanya muncul</strong> jika Total Remake 3 atau lebih. Anda wajib jelaskan kenapa banyak gagal</td></tr></tbody></table><p><strong>Bagian Bawah — Detail Per Komplain:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Contoh</th></tr></thead><tbody><tr><td><strong>Jam &amp; Inisial Pelanggan</strong></td><td>&quot;14:30&quot; dan &quot;Bpk. A&quot;</td></tr><tr><td><strong>Isi Komplain</strong></td><td>&quot;Matcha terlalu manis&quot;</td></tr><tr><td><strong>Tindakan (Respon)</strong></td><td>&quot;Minta maaf, dibuatkan ulang yang baru&quot;</td></tr><tr><td><strong>Checkbox Remake/Eskalasi</strong></td><td>Centang &quot;Remake&quot; jika produk dibikin ulang. Centang &quot;Eskalasi GM&quot; jika butuh perhatian owner</td></tr></tbody></table><h3 id="_3-9-tab-8-fasilitas-bahan" tabindex="-1">3.9 Tab 8: FASILITAS &amp; BAHAN <a class="header-anchor" href="#_3-9-tab-8-fasilitas-bahan" aria-label="Permalink to &quot;3.9 Tab 8: FASILITAS &amp; BAHAN&quot;">​</a></h3><p>Tab ini merekam kerusakan alat dan kebutuhan belanja bahan habis pakai. Gunakan tombol <strong>&quot;TAMBAH&quot;</strong> dan <strong>&quot;HAPUS&quot;</strong> sesuai kebutuhan.</p><p><strong>A. Fasilitas &amp; Alat (Kerusakan)</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Nama Alat/Fasilitas</strong></td><td>Contoh: &quot;AC Lantai 1&quot;, &quot;Grinder&quot;</td></tr><tr><td><strong>Status Kerusakan</strong></td><td>Rusak Ringan / Rusak Sedang / Rusak Berat (Mati)</td></tr><tr><td><strong>Eskalasi GM?</strong></td><td>Tekan kotak merah jika butuh perbaikan cepat dari owner</td></tr><tr><td><strong>Keterangan Singkat</strong></td><td>Contoh: &quot;Bocor freon, air menetes&quot;</td></tr><tr><td><strong>Tombol Unggah Foto</strong></td><td>Ambil/lampirkan foto bukti kerusakan. Setelah unggah, berubah jadi &quot;Lihat Foto&quot; &amp; &quot;Hapus Foto&quot;</td></tr></tbody></table><p><strong>B. Bahan &amp; ATK Habis</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Nama Bahan</strong></td><td>Contoh: &quot;Sabun Cuci&quot;, &quot;Tisu&quot;</td></tr><tr><td><strong>Status Ketersediaan</strong></td><td>Contoh: &quot;Habis&quot;, &quot;Sisa 1 Botol&quot;</td></tr><tr><td><strong>Estimasi Harga (Rp)</strong></td><td>Perkiraan biaya untuk reimburse</td></tr><tr><td><strong>Tombol Unggah Bukti</strong></td><td>Foto nota belanja atau kondisi barang yang kosong</td></tr></tbody></table><blockquote><p><strong>Penyimpanan Foto Otomatis:</strong> Semua foto yang Anda unggah akan otomatis tersortir ke folder yang benar di Google Drive:</p><ul><li>Foto kerusakan alat → masuk folder <strong><code>Fasilitas</code></strong></li><li>Foto nota belanja/bahan → masuk folder <strong><code>Pengeluaran</code></strong></li></ul><p>Nama file juga otomatis diganti menjadi format cerdas, contoh: <code>18-07-ACLantai1-RusakBerat.jpg</code> — sehingga GM mudah mencari di kemudian hari.</p></blockquote><h3 id="_3-10-tab-9-tutup-kesimpulan-pengiriman" tabindex="-1">3.10 Tab 9: TUTUP (Kesimpulan &amp; Pengiriman) <a class="header-anchor" href="#_3-10-tab-9-tutup-kesimpulan-pengiriman" aria-label="Permalink to &quot;3.10 Tab 9: TUTUP (Kesimpulan &amp; Pengiriman)&quot;">​</a></h3><p>Ini adalah tab terakhir sebelum laporan dikirim.</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Kendala Utama Hari Ini</strong></td><td>Ringkasan kesulitan paling mengganggu selama shift</td></tr><tr><td><strong>Rekomendasi / Saran</strong></td><td>Permintaan ke manajemen atau solusi strategis dari Anda</td></tr></tbody></table><p><strong>Dua Tombol di Bawah:</strong></p><table tabindex="0"><thead><tr><th>Tombol</th><th>Fungsi</th></tr></thead><tbody><tr><td><strong>BATAL</strong></td><td>Kembali ke Menu Utama. Data yang sudah diketik <strong>tidak hilang</strong> (tersimpan otomatis)</td></tr><tr><td><strong>KIRIM LAPORAN SOP</strong></td><td>Mengirim laporan ke server</td></tr></tbody></table><p><strong>Apa yang terjadi saat Anda tekan &quot;KIRIM&quot;?</strong></p><ol><li><strong>Jika ada data yang belum lengkap:</strong> Muncul peringatan merah yang menyebutkan bagian mana yang belum diisi. Laporan <strong>ditolak</strong> sampai Anda melengkapinya.</li><li><strong>Jika semua data lengkap:</strong> Muncul jendela <strong>Pratinjau (Preview)</strong> besar yang menampilkan tampilan PDF laporan Anda. Periksa sekali lagi, lalu tekan <strong>&quot;Kirim Final&quot;</strong> di dalam jendela tersebut.</li></ol><h3 id="_3-11-fase-2-penyelesaian-keesokan-pagi" tabindex="-1">3.11 Fase 2 (Penyelesaian Keesokan Pagi) <a class="header-anchor" href="#_3-11-fase-2-penyelesaian-keesokan-pagi" aria-label="Permalink to &quot;3.11 Fase 2 (Penyelesaian Keesokan Pagi)&quot;">​</a></h3><p>Saat Anda membuka aplikasi keesokan harinya, jika ada Laporan Harian yang tertunda (Fase 1 sudah terkirim tapi Fase 2 belum), sistem akan otomatis menampilkan formulir Fase 2.</p><p><strong>A. Data Keuangan Malam:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Omset Shift 2 (Rp)</strong></td><td>Penjualan shift malam. Otomatis dijumlahkan dengan Shift 1 untuk membentuk <strong>Total Omset Harian</strong></td></tr><tr><td><strong>Total Struk Transaksi</strong></td><td>Jumlah total struk hari itu (Shift 1 + Shift 2). Angka ini digunakan mesin AI untuk menghitung <strong>Rata-rata Belanja per Pelanggan (ATS)</strong></td></tr></tbody></table><p><strong>B. Evaluasi Produk:</strong></p><p>Untuk setiap kategori (Minuman, Makanan, Snack):</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Top 5 Produk</strong></td><td>5 menu paling laris hari itu</td></tr><tr><td><strong>Bottom 3 Produk</strong></td><td>3 menu paling tidak laku</td></tr><tr><td><strong>Alasan Bottom 3</strong></td><td>Kenapa produk ini tidak laku (Contoh: &quot;Bahan habis&quot;, &quot;Tidak ada promo&quot;)</td></tr></tbody></table><p><strong>C. Operasional Malam:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Komplain Susulan (Malam)</strong></td><td>Jika ada insiden malam, tambahkan di sini (sama dengan Tab 7)</td></tr><tr><td><strong>Absensi &amp; SOP Staf Malam</strong></td><td>Evaluasi kehadiran dan keramahan staf closing (sama dengan Tab 3)</td></tr></tbody></table><blockquote><p><strong>Perlindungan Data Usang:</strong> Jika besok Anda membuka aplikasi dan ternyata server sudah tidak punya catatan Fase 1 yang tertunda (misalnya karena sudah diproses atau dibatalkan), tapi HP Anda masih menyimpan sisa data kemarin, sistem akan otomatis <strong>membuang data usang tersebut</strong>. Ini mencegah data hari kemarin tercampur dengan hari ini.</p></blockquote><hr>',65)])])}const m=t(e,[["render",s]]);export{h as __pageData,m as default};
